-- 1. Letting Agents × Web Design
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'letting-agents',
  'web-design',
  'Letting agents face a unique digital challenge: your website must serve two entirely different audiences simultaneously. Tenants need to browse available properties, book viewings, and submit applications seamlessly. Landlords need to see evidence of professional management, transparent fee structures, and compelling reasons to switch from their current agent or self-management. Most letting agent websites fail at both — clunky property search tools frustrate tenants, while generic "why choose us" sections fail to convince landlords that this agency will protect their investment and maximise yield. Meanwhile, Rightmove and Zoopla dominate property search, making your own website feel redundant unless it offers something the portals cannot. We build letting agent websites that convert landlords through compelling property management content and provide tenants with a frictionless search-to-viewing experience that complements your portal listings.',
  'Your website is the primary tool for landlord acquisition — the highest-value activity in any letting agency. When a landlord searches for local letting agents, your site must instantly communicate professionalism, local market knowledge, and management capability. For tenants, a smooth property search and viewing booking experience reduces your admin burden and fills vacancies faster. A purpose-built letting agent website serves both audiences without compromise.',
  'We design letting agent sites with distinct landlord and tenant journeys. Landlord-facing pages feature rental yield data, management service breakdowns, and free valuation tools. Tenant-facing sections integrate with your property management software for real-time availability, online viewing bookings, and application submissions.',
  '[{"title": "Website cannot compete with Rightmove and Zoopla for tenant traffic", "description": "Letting agents struggle to drive tenant traffic to their own websites when Rightmove and Zoopla dominate property search. Without a clear value proposition beyond the portals — such as early access listings, detailed neighbourhood guides, or seamless application processes — your website becomes an afterthought for property seekers."}, {"title": "No dedicated landlord acquisition journey on the website", "description": "Most letting agent websites bury landlord content behind a single ''Landlords'' tab with generic promises. Without dedicated landing pages addressing specific landlord concerns — void periods, legal compliance, rent guarantees, property maintenance — the site fails to convert the prospects who represent your highest-value revenue stream."}, {"title": "Property listings not synced with management software", "description": "Manually updating website listings when properties become available or are let creates delays and inaccuracies. Tenants encountering properties marked as available that are already let lose trust, and your team wastes hours maintaining duplicate listing systems."}]',
  '[{"title": "Dual-journey design for landlords and tenants", "description": "We build letting agent websites with clearly separated landlord and tenant experiences. Landlords see rental yield calculators, management service breakdowns, compliance assurance content, and prominent free valuation calls-to-action. Tenants access fast property search, viewing booking tools, and streamlined application forms."}, {"title": "Landlord acquisition landing pages with conversion focus", "description": "Dedicated pages targeting specific landlord segments — first-time landlords, portfolio landlords, landlords switching agents, and self-managing landlords considering professional management — each address the specific concerns and motivations of that audience with tailored content and calls to action."}, {"title": "Property management software integration", "description": "We integrate your website with property management platforms like Arthur, Reapit, or Street.co.uk for real-time listing synchronisation. Properties appear and disappear automatically as availability changes, viewing slots update in real time, and tenant applications feed directly into your management workflow."}]',
  '[{"question": "Should our letting agent website focus on landlords or tenants?", "answer": "Both, but with strategic priority. Landlord acquisition drives long-term revenue, so landlord-facing content receives prominent positioning and dedicated conversion paths. Tenant-facing property search and application tools reduce your operational workload and fill vacancies faster, supporting the service quality that retains landlords."}, {"question": "Can the website integrate with our property management software?", "answer": "Yes. We integrate with most major letting agent platforms including Arthur, Reapit, Street.co.uk, and others. Property listings sync automatically, viewing availability updates in real time, and tenant applications flow directly into your management system without manual data entry."}, {"question": "How do we compete with Rightmove and Zoopla for website traffic?", "answer": "Your website should not try to replace the portals for general property search. Instead, it should offer what they cannot: detailed neighbourhood guides, early access to new listings, landlord-focused content, and a seamless application process. This drives direct traffic from landlords and engaged tenants who value the enhanced experience."}, {"question": "Can tenants book viewings directly through the website?", "answer": "Yes. We build online viewing booking systems that display available time slots synced with your team''s calendars. Tenants select a property, choose a convenient slot, and receive automatic confirmation. This reduces phone calls, eliminates scheduling conflicts, and provides a professional tenant experience."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 2. Letting Agents × SEO
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'letting-agents',
  'seo',
  'SEO for letting agents is a battle on two fronts: ranking for tenant property searches against the enormous domain authority of Rightmove, Zoopla, and OnTheMarket, and ranking for landlord acquisition searches where the competition is other local agents. The landlord front is where SEO delivers the highest ROI. When a landlord searches "letting agents in Maidstone" or "property management fees Kent," appearing above your competitors directly generates the instructions that grow your portfolio. On the tenant side, local SEO and neighbourhood content can capture searches the portals handle poorly — "pet-friendly rentals Canterbury" or "best areas to rent in Medway." A letting agent SEO strategy must prioritise landlord acquisition keywords while building a content moat around local property market expertise that the national portals cannot replicate. We build SEO campaigns for letting agents that focus on the searches that actually grow your managed portfolio and fill your properties faster.',
  'Letting agents who rely solely on portal listings for tenant traffic and word of mouth for landlord acquisition are ceding control of their growth to third parties. SEO delivers a direct pipeline of landlords actively searching for management services and tenants seeking properties in your area. Ranking for "letting agent" plus your location terms captures landlords at their highest point of intent, while local property market content builds the authority that sustains those rankings long-term.',
  'We prioritise landlord acquisition keywords — "letting agent [location]," "property management [area]," "landlord services [town]" — because these searches directly drive portfolio growth. Tenant-facing SEO focuses on hyper-local neighbourhood content and niche property type searches that Rightmove handles poorly, capturing traffic the portals miss.',
  '[{"title": "Rightmove and Zoopla dominating property search rankings", "description": "National property portals have enormous domain authority and sophisticated SEO operations. Letting agents attempting to rank for generic property search terms like ''flats to rent in [town]'' face near-impossible competition. Without a strategy targeting searches the portals handle poorly, your organic property search traffic will remain negligible."}, {"title": "Invisible for landlord acquisition searches", "description": "When landlords search for letting agents or property management services, the agencies appearing on page one capture the majority of new instructions. Without deliberate SEO targeting these high-value searches, your agency is invisible to landlords actively looking to appoint a new managing agent."}, {"title": "No local property market content building authority", "description": "Letting agents who publish no content about local rental market conditions, yield data, or area guides miss the opportunity to build topical authority that Google rewards with higher rankings. Competitors publishing regular market commentary steadily outrank agencies with static, content-thin websites."}]',
  '[{"title": "Landlord acquisition keyword domination", "description": "We build dedicated, optimised pages targeting every variation of landlord acquisition search terms for your area — letting agents, property management, landlord services, rental management, portfolio management. Each page addresses specific landlord needs and drives toward free valuation or consultation requests."}, {"title": "Local rental market content strategy", "description": "Regular publication of local rental market analysis — average yields by area, demand trends, regulatory updates, and neighbourhood rental guides — builds the topical authority that Google rewards with higher rankings. This content also demonstrates the market expertise that convinces landlords to instruct your agency."}, {"title": "Niche property search pages targeting portal gaps", "description": "We create content targeting property searches that Rightmove handles poorly: pet-friendly rentals, specific neighbourhood guides, property type specialists, and long-term let specialists. These long-tail searches generate tenant traffic directly to your site, bypassing portal dependency for engaged, qualified applicants."}]',
  '[{"question": "Can a letting agent really outrank Rightmove for property searches?", "answer": "For broad terms like ''flats to rent,'' no. But for specific local and niche searches — neighbourhood-specific queries, pet-friendly properties, particular property types — a well-optimised local letting agent site can absolutely outrank the portals. We focus on these winnable searches rather than fighting unwinnable battles."}, {"question": "How does SEO help with landlord acquisition?", "answer": "When landlords search for letting agents or property management services in your area, SEO determines whether your agency appears on the first page. We optimise for every variation of these searches, ensuring your agency is visible to landlords actively looking to instruct a new agent — the highest-value leads in the letting industry."}, {"question": "What content should a letting agent publish for SEO?", "answer": "Local rental market updates, yield analysis by area, landlord guides covering legal compliance and regulations, neighbourhood rental guides, and tenant advice content. This mix targets both landlord and tenant search intent while building the topical authority that sustains rankings long-term."}, {"question": "How long before SEO generates new landlord instructions?", "answer": "Landlord acquisition keywords typically show ranking improvements within eight to twelve weeks, with first-page positions for less competitive location terms often achieved within four to six months. The compounding nature of SEO means that results accelerate over time as your site builds authority through consistent content publication."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
