  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 3. Letting Agents × Lead Capture
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'letting-agents',
  'lead-capture',
  'The most valuable visitor to a letting agent''s website is a landlord considering professional management — and most of these visitors leave without identifying themselves. They browse your fees page, read a service description, perhaps check a few property listings, and then disappear to research competitors. Without lead capture mechanisms designed specifically for the letting industry, you have no way to follow up with these high-value prospects. Effective lead capture for letting agents means offering genuinely useful tools that landlords want to engage with: instant online property valuations, rental yield calculators, free landlord compliance checklists, and downloadable guides on topics like Section 21 changes or EPC regulations. For tenant-facing capture, property alert sign-ups and application pre-qualification forms keep prospective tenants engaged when no suitable property is currently available. We build lead capture systems for letting agents that convert anonymous website visitors into identifiable, contactable landlord and tenant prospects.',
  'Landlord acquisition is the growth engine of any letting agency, and most landlord prospects visit your website multiple times before making contact. Lead capture tools — property valuations, yield calculators, compliance guides — give landlords a reason to share their details early in the research process, allowing you to nurture them through to instruction. Without these mechanisms, you rely entirely on landlords picking up the phone, losing the majority who prefer to research privately.',
  'We build landlord-specific lead magnets: instant online rental valuations powered by local market data, rental yield calculators for investment landlords, and downloadable compliance guides covering current legislation. Each tool captures the landlord''s property details and contact information, feeding qualified leads directly into your CRM.',
  '[{"title": "Landlord prospects researching but not making contact", "description": "Landlords considering switching agents or moving to professional management visit multiple agency websites before deciding. Without a compelling reason to share their details — like a free property valuation or yield calculation — these high-value prospects remain anonymous and uncontactable during their critical decision period."}, {"title": "No lead magnets addressing current landlord concerns", "description": "Legislative changes, EPC requirements, selective licensing, and Section 21 reform create genuine anxiety among landlords. Letting agents who offer no downloadable guides, checklists, or tools addressing these specific concerns miss the opportunity to capture leads from landlords actively seeking expert guidance."}, {"title": "Tenant enquiries lost when no suitable property is available", "description": "Tenants who search your listings and find nothing suitable leave your site permanently. Without property alert registration or waiting list sign-ups, you cannot reconnect with these qualified tenants when a matching property becomes available, forcing you to restart marketing for every vacancy."}]',
  '[{"title": "Instant online rental valuation tool", "description": "A property valuation form captures the landlord''s address, property type, bedrooms, and condition, then provides an estimated rental value based on comparable local data. The landlord receives a useful valuation; you receive a qualified lead with full property details and contact information ready for follow-up."}, {"title": "Landlord compliance checklist and regulatory guides", "description": "Downloadable guides covering current landlord obligations — EPC requirements, gas safety regulations, deposit protection, licensing requirements — capture email addresses from concerned landlords. A follow-up email sequence demonstrates your compliance expertise and positions your agency as the safe choice for professional management."}, {"title": "Tenant property alert registration", "description": "When no suitable property is currently listed, tenants register their requirements — location, bedrooms, budget, move-in date — and receive automatic notifications when matching properties become available. This builds a waiting list of qualified tenants, reducing void periods when new properties come under management."}]',
  '[{"question": "What is the best lead magnet for attracting landlords?", "answer": "An instant online rental valuation consistently generates the highest volume and quality of landlord leads. Landlords are naturally curious about their property''s rental value, and providing this information in exchange for contact details creates a natural opening for follow-up discussions about management services."}, {"question": "How does the rental valuation tool work?", "answer": "The landlord enters their property address, type, bedrooms, and condition. The tool calculates an estimated rental value based on comparable local market data. They receive the valuation via email, and you receive their full property details and contact information as a qualified lead in your CRM."}, {"question": "Can lead capture help reduce void periods?", "answer": "Yes. Tenant property alert registrations build a pre-qualified waiting list of tenants actively seeking rentals in your area. When a new property comes under management, you can immediately notify matching tenants, often securing viewings and applications before the property even hits the portals."}, {"question": "How do captured landlord leads get followed up?", "answer": "Leads feed directly into your CRM with full property and contact details. An automated email sequence delivers relevant content — local market data, management service information, client testimonials — over the following weeks. Your team receives instant notifications for high-priority leads flagged for personal follow-up."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
