-- 6. Letting Agents × Social Media Setup
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'letting-agents',
  'social-media-setup',
  'Social media for letting agents serves a dual commercial purpose that most agencies completely overlook. For tenant acquisition, platforms like Facebook and Instagram showcase available properties with walkthrough videos and lifestyle content about your operating areas. For landlord acquisition — the far more valuable objective — LinkedIn and local business networks position your agency as a market authority, while community Facebook posts demonstrate local expertise and active management. Yet most letting agents either have no social presence or post sporadically with generic property listings that generate zero engagement. Setting up social media properly for a letting agency means creating distinct content strategies for landlord and tenant audiences, establishing branded templates for property showcases and market updates, and building a sustainable posting framework that your team can maintain alongside day-to-day agency operations. We set up and optimise letting agent social media with clear audience segmentation and content systems that drive both landlord instructions and tenant enquiries.',
  'Landlords increasingly research letting agents on social media before making contact, looking for evidence of active management, market knowledge, and professional operations. An agency with no social presence or dormant accounts raises questions about its viability and commitment. Regular social content demonstrating local market expertise, successful lets, and tenant satisfaction builds the confidence that converts researching landlords into instructing clients.',
  'We set up letting agent social accounts with dual content streams: landlord-focused content on LinkedIn and Facebook featuring market data, regulatory updates, and portfolio highlights; tenant-focused content on Instagram and Facebook showcasing available properties, area guides, and moving tips. Branded templates make consistent posting achievable.',
  '[{"title": "No social media presence despite managing local properties", "description": "Letting agents managing dozens of properties across residential areas have zero social media presence. Every successful let, satisfied tenant, and market insight goes unshared, while competitors who post consistently build the online authority and visibility that attracts new landlord instructions."}, {"title": "Social posts that only list available properties with no engagement", "description": "Agencies that use social media solely to post property listings generate minimal engagement. Without market commentary, landlord-relevant content, area guides, and behind-the-scenes management insights, their social presence feels like an automated feed rather than an active, knowledgeable agency."}, {"title": "No LinkedIn strategy for landlord acquisition", "description": "LinkedIn is the most effective platform for reaching professional landlords and property investors, yet most letting agents have minimal or no LinkedIn presence. Without thought leadership content, market analysis posts, and professional networking activity, agencies miss the highest-value audience on social media."}]',
  '[{"title": "Dual-audience social media profiles", "description": "We set up Facebook and Instagram for tenant-facing property showcases and community engagement, and LinkedIn for landlord-focused market commentary and professional positioning. Each platform has distinct content strategies, branded templates, and posting schedules aligned to its primary audience."}, {"title": "Property showcase templates for consistent listings", "description": "Branded templates for Instagram carousels, Facebook property posts, and story walkthroughs ensure every listing looks professional and consistent. Photo guidelines and video frameworks enable your team to create compelling property content quickly using smartphone cameras during routine property visits."}, {"title": "Market insight content calendar for landlord audience", "description": "A twelve-month content calendar includes local rental market updates, regulatory change summaries, yield analysis by area, and landlord advice content. These posts position your agency as a knowledgeable market authority on LinkedIn and Facebook, building the credibility that drives landlord instructions."}]',
  '[{"question": "Which social platforms are most important for letting agents?", "answer": "Facebook and Instagram are essential for property showcases and local community engagement with both tenants and landlords. LinkedIn is critical for landlord acquisition, particularly for reaching professional landlords and property investors. We set up all three platforms with distinct strategies for each audience."}, {"question": "How can social media help attract new landlords?", "answer": "Regular posts demonstrating local market knowledge — rental yield data, demand trends, regulatory updates — position your agency as the informed, authoritative choice. Case studies of successful lets, portfolio growth updates, and client testimonials build confidence in your management capabilities and generate landlord enquiries."}, {"question": "How often should a letting agent post on social media?", "answer": "We recommend four to five posts per week across platforms: two to three property showcases on Instagram and Facebook, one market insight post on LinkedIn, and one community or behind-the-scenes post. Branded templates and scheduled content make this achievable in under an hour per week."}, {"question": "Can property listings be posted automatically to social media?", "answer": "We can set up workflows that generate social media draft posts when new properties are added to your management software. Your team reviews and approves each post before publication, ensuring brand consistency while dramatically reducing the time needed to maintain a regular property showcase presence."}]'
)
