-- 8. Letting Agents × Workwear & Print
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'letting-agents',
  'workwear-print',
  'A letting agent''s physical presence extends far beyond the office: property viewings, inspections, landlord meetings, check-ins, and contractor supervision all place your team in the public eye across residential neighbourhoods. Branded workwear ensures that every property visit reinforces your professional image, while printed materials — property particulars, landlord information packs, tenant welcome folders, and business cards — shape the perception of your agency at critical decision-making moments. When a landlord receives a property valuation presentation in a branded folder with professionally designed particulars, they are experiencing your brand promise in physical form. When a tenant receives a branded welcome pack at check-in, they are forming their first impression of the management relationship. Most letting agents underinvest in these physical touchpoints, presenting proposals in generic folders and sending staff to viewings in unbranded clothing. We provide letting agents with complete branded workwear, printed materials, and physical marketing assets that reinforce professionalism at every in-person interaction.',
  'Letting agents conduct dozens of property visits, viewings, and meetings each week in residential areas. Every in-person interaction is an opportunity to reinforce brand professionalism — or undermine it through inconsistent presentation. Branded workwear identifies your staff as professional representatives, printed particulars and proposals demonstrate attention to detail, and leave-behind materials generate future enquiries. Physical touchpoints carry disproportionate weight in building the trust that drives landlord instructions.',
  'We supply letting agent teams with professional branded workwear suitable for property viewings and client meetings — polo shirts, oxford shirts, softshell jackets, and lanyards. Printed materials include property particulars templates, landlord valuation presentation folders, tenant welcome packs, and branded stationery.',
  '[{"title": "Staff attending viewings and meetings without branding", "description": "Letting agents sending staff to property viewings, landlord meetings, and inspections in unbranded clothing miss every opportunity to reinforce their professional identity. Landlords and tenants cannot distinguish your representative from any other visitor, and the agency appears less established than branded competitors."}, {"title": "Property particulars and proposals presented informally", "description": "Landlord valuation proposals printed on plain paper and property particulars without consistent branding undermine the professional image your agency depends on. When competing against agents who present polished, branded documents, informal presentation costs you instructions and lets."}, {"title": "No branded materials to leave behind after viewings and visits", "description": "After property viewings, inspections, and landlord meetings, your team leaves no branded material that reinforces your agency''s presence. Business cards are often generic, and there is no branded information for tenants or landlords to reference when making their decision."}]',
  '[{"title": "Professional branded workwear for property-facing staff", "description": "We supply branded polo shirts, oxford shirts, and softshell jackets for viewing agents, property managers, and maintenance coordinators. Branded lanyards and name badges add a further layer of professionalism. All items are comfortable for active property visits while maintaining a polished appearance for landlord meetings."}, {"title": "Branded property particulars and presentation materials", "description": "Professional property particular templates with your branding, high-quality photography layouts, and consistent formatting across every listing. Landlord valuation presentations are delivered in branded folders with market data, fee structures, and service breakdowns that demonstrate the quality of your agency''s operations."}, {"title": "Tenant welcome packs and landlord onboarding folders", "description": "Branded tenant welcome packs containing property information, maintenance reporting procedures, and agency contact details create a positive first impression at check-in. Landlord onboarding folders with management agreements, compliance documentation, and key contact details reinforce the professional relationship from instruction onwards."}]',
  '[{"question": "What workwear is appropriate for letting agent staff?", "answer": "We recommend branded polo shirts for routine property visits and inspections, oxford shirts for landlord meetings and formal viewings, and softshell jackets for outdoor work and cold-weather visits. Branded lanyards with ID badges add security credibility for property access. All items are designed for comfort during active property work."}, {"question": "Can you produce branded property particulars templates?", "answer": "Yes. We design property particular templates that your team can populate with photography and details for each listing. Templates maintain consistent branding across all properties while allowing customisation for individual listings. We provide these in editable formats compatible with your current design software or management system."}, {"question": "Do you supply tenant welcome packs?", "answer": "Yes. We design and print branded tenant welcome packs including property-specific information sheets, maintenance reporting guides, agency contact details, and move-in checklists. These create a professional first impression at check-in and provide tenants with essential information in a branded format."}, {"question": "How quickly can branded materials be produced?", "answer": "Workwear orders typically take seven to ten working days. Printed materials including property particulars, presentation folders, and welcome packs are produced within five to seven working days. Rush orders can often be accommodated for urgent requirements. We recommend keeping standard stock levels to avoid running out."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 9. Letting Agents × AI Chatbots
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'letting-agents',
  'ai-chatbots',
  'Letting agents handle a relentless volume of repetitive enquiries: tenants asking about property availability, viewing times, application requirements, and maintenance reporting; landlords asking about fees, services, market conditions, and their current property status. Each enquiry demands a timely response, and delayed replies cost you tenants to faster-responding agents and landlords to competitors who seem more attentive. An AI chatbot built for letting agents handles both audience types intelligently. For tenants, it answers property availability questions in real time, books viewings from your team''s calendar, explains application requirements, and captures details for the waiting list when no suitable property is listed. For landlords, it provides information about your management services, captures property details for free valuation requests, and answers preliminary questions about fees, compliance support, and management processes. We build AI chatbots specifically trained on letting agency operations that reduce your team''s repetitive workload while ensuring every visitor receives an instant, helpful response.',
  'Letting agents lose tenant leads to faster-responding competitors and landlord prospects to agencies that seem more attentive. An AI chatbot provides instant responses to both audiences around the clock: booking viewings for tenants at eleven o''clock at night and capturing landlord valuation requests on Sunday mornings. This responsiveness directly reduces void periods, accelerates landlord acquisition, and frees your team from the repetitive enquiries that consume their productive hours.',
  'Our letting agent chatbots handle dual audiences: tenant-facing conversations around property search, viewing bookings, and application guidance; landlord-facing conversations around services, fees, and valuation requests. The chatbot routes high-value landlord enquiries for priority follow-up while managing tenant interactions autonomously.',
  '[{"title": "Tenant enquiries overwhelming the team during office hours", "description": "Property availability questions, viewing requests, application queries, and maintenance reports flood letting agents during business hours. Staff spend the majority of their time answering repetitive questions rather than conducting viewings, managing properties, or acquiring new landlord instructions."}, {"title": "Landlord prospects visiting the website outside business hours", "description": "Landlords often research letting agents during evenings and weekends when your office is closed. Without an instant response mechanism, these high-value prospects move on to competitor websites, and by Monday morning they may have already booked valuations with rival agencies."}, {"title": "Slow response times losing tenants to competing agents", "description": "In a competitive rental market, tenants contact multiple agents simultaneously. The first agency to respond and book a viewing typically secures the application. Without instant response capability, your agency loses qualified tenants to competitors who reply faster, extending void periods and frustrating landlords."}]',
  '[{"title": "Instant tenant engagement with viewing booking", "description": "The chatbot answers property availability questions in real time using your current listings data, books viewings directly into your team''s calendar, explains application requirements and fees, and registers waiting list tenants when no suitable property is available — all without requiring staff intervention."}, {"title": "Landlord enquiry capture and qualification", "description": "Landlord visitors receive immediate information about your management services, fee structures, and approach. The chatbot captures property details for free valuation requests, asks qualifying questions about portfolio size and current management arrangements, and routes high-value prospects for priority personal follow-up."}, {"title": "Maintenance request logging and triage", "description": "Tenants can report maintenance issues through the chatbot at any time. The system captures details, photographs, and urgency level, logs the request in your management system, and provides the tenant with a reference number and expected response timeline — reducing phone calls and ensuring consistent documentation."}]',
  '[{"question": "Can the chatbot handle both tenant and landlord conversations?", "answer": "Yes. The chatbot identifies whether the visitor is a tenant or landlord based on their initial query and adjusts its responses accordingly. Tenant conversations focus on property search, viewings, and applications. Landlord conversations cover services, fees, and valuation requests. Each path is designed to maximise conversion for that audience."}, {"question": "Will the chatbot have access to our current property listings?", "answer": "Yes. We integrate the chatbot with your property management system so it can answer availability questions in real time, provide basic property details, and confirm whether specific properties are still available. This ensures tenants receive accurate, current information without staff involvement."}, {"question": "How does the chatbot handle emergency maintenance reports?", "answer": "The chatbot identifies emergency keywords — flood, leak, no heating, gas smell — and immediately provides relevant safety instructions while escalating the report to your emergency contact. Non-emergency maintenance is logged with full details and confirmation for standard response processing."}, {"question": "Can the chatbot book property viewings autonomously?", "answer": "Yes. The chatbot accesses your team''s viewing availability calendar and allows tenants to select convenient slots. Confirmation is sent to both the tenant and the viewing agent. If a viewing requires specific arrangements such as key collection, the chatbot includes these instructions automatically."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
