  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 10. Letting Agents × AI Content
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'letting-agents',
  'ai-content',
  'Letting agents need to publish two categories of content consistently: landlord-facing market analysis, regulatory updates, and investment guidance that demonstrates expertise and drives instructions; and tenant-facing area guides, renting advice, and property lifestyle content that builds search visibility and attracts applicants. Most agencies produce neither, because the team is consumed by day-to-day property management and has no time for content creation. AI-powered content creation for letting agents solves this by generating expert-level property market commentary, regulatory analysis, neighbourhood rental guides, and tenant advice — all calibrated to your local market, current legislation, and agency positioning. Every piece is optimised for the search terms landlords and tenants actually use, structured to drive conversions, and published consistently to build the content authority that compounds into lasting competitive advantage. We set up AI content systems for letting agents that maintain a steady stream of authoritative, locally relevant content without requiring your team to write a word.',
  'Content marketing for letting agents builds the topical authority that drives both landlord acquisition and tenant search visibility. Regular market commentary positions your agency as a knowledgeable local expert, attracting landlords who want informed management. Tenant-facing area guides and renting advice capture search traffic from prospective tenants researching locations. Without consistent content, your website stagnates while competitors publishing regularly accumulate the search authority that generates instructions and applications.',
  'Our AI content system produces letting-specific material: local rental yield analyses, legislative update summaries relevant to your landlords, neighbourhood guides with rental market context, and seasonal renting advice. Content references current regulations, local market data, and area-specific insights that demonstrate genuine letting expertise.',
  '[{"title": "No time for content creation alongside property management", "description": "Letting agency teams spend their days managing tenancies, conducting viewings, handling maintenance, and acquiring instructions. Writing blog posts about rental market trends or landlord regulations gets deprioritised indefinitely, leaving the website static and invisible for content-driven searches."}, {"title": "Competitor agencies building content authority", "description": "Forward-thinking letting agents publishing regular market analysis, regulatory updates, and area guides are accumulating search authority that compounds month by month. Without matching this output, your agency falls progressively behind in rankings for both landlord and tenant search terms."}, {"title": "Regulatory updates not being communicated to landlords", "description": "Frequent legislative changes — EPC requirements, Renters Reform Bill, deposit regulations, licensing changes — create opportunities to demonstrate expertise and add value to landlord relationships. Without content covering these updates, your agency misses the chance to position itself as an informed, proactive management partner."}]',
  '[{"title": "Local rental market analysis and commentary", "description": "AI generates monthly rental market reports for your operating area: average rents by property type, yield comparisons, demand trends, and forward-looking commentary. Published as blog posts and shared on social media, this content demonstrates the market knowledge that convinces landlords to trust your management recommendations."}, {"title": "Regulatory update content for landlord audience", "description": "When legislation changes affect landlords — EPC deadlines, licensing requirements, safety regulations, tenancy law updates — AI produces clear, practical summaries explaining the implications and your agency''s compliance support. This content builds trust, drives search traffic, and provides genuine value to your landlord client base."}, {"title": "Neighbourhood rental guides for tenant acquisition", "description": "Detailed area guides covering rental market conditions, local amenities, transport links, and lifestyle factors for each neighbourhood you operate in. These guides capture tenant search traffic, improve your site''s local search authority, and provide valuable content to share with prospective tenants during their property search."}]',
  '[{"question": "What types of content does AI produce for letting agents?", "answer": "Local rental market reports, landlord regulatory updates, neighbourhood guides, tenant advice articles, property listing descriptions, social media posts, email newsletter content, and Google Business Profile updates. The content mix is tailored to your primary business objectives — whether that is landlord acquisition, tenant attraction, or both."}, {"question": "Will AI content reflect current letting regulations accurately?", "answer": "Yes. The system is updated with current letting legislation and regulatory requirements. Content covering legal topics includes appropriate caveats and references to official guidance. We recommend a brief review of regulatory content before publication to ensure alignment with the most recent developments affecting your area."}, {"question": "How does content help with landlord acquisition specifically?", "answer": "Market analysis posts, yield data, and regulatory updates attract landlords searching for local market information. This content demonstrates the expertise that distinguishes a knowledgeable agency from a passive listing service. Landlords who read your market commentary before making contact arrive as warmer, more qualified prospects."}, {"question": "Can AI generate property listing descriptions?", "answer": "Yes. The AI produces compelling, unique property descriptions based on your property details, photographs, and area information. This saves considerable time compared to writing descriptions from scratch for each listing and ensures consistent quality across your entire portfolio."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
