  faqs = EXCLUDED.faqs;

-- 11. Letting Agents × AI Automation
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'letting-agents',
  'ai-automation',
  'Letting agency operations generate vast quantities of structured, repetitive decision-making: screening tenant applications against landlord criteria, categorising and routing maintenance requests by urgency and trade, generating rental market comparables for valuations, and producing landlord reports from management data. AI automation brings intelligent processing to these tasks, making decisions that currently require staff time but follow consistent, documentable logic. An AI system can pre-screen tenant applications against affordability ratios and landlord preferences before your team reviews them, categorise maintenance photographs to identify the correct trade and urgency level, generate comparative market analysis reports for landlord valuations in minutes rather than hours, and produce personalised monthly landlord reports summarising management activity, financial performance, and market conditions. These are not futuristic concepts — they are practical AI applications that transform letting agency efficiency today. We build AI automation systems for letting agents that handle the intelligent repetitive work consuming your team''s capacity.',
  'Letting agency profitability is constrained by the ratio of managed properties to staff members. Every hour spent on routine screening, categorisation, and reporting is an hour not spent on landlord acquisition, relationship management, and strategic growth. AI automation handles the high-volume intelligent tasks that bottleneck scaling — application screening, maintenance triage, market analysis, and reporting — enabling your team to manage a significantly larger portfolio without proportional headcount growth.',
  'We build AI automations for letting-specific workflows: tenant application pre-screening against landlord criteria, maintenance request image analysis for trade routing and urgency classification, automated comparable market analysis for rental valuations, and AI-generated monthly landlord management reports with portfolio performance insights.',
  '[{"title": "Tenant application screening consuming hours of staff time", "description": "Each tenant application requires verification of employment, income, references, and credit history against the landlord''s criteria. With multiple applications per property and dozens of properties turning over annually, manual screening consumes enormous staff hours that could be spent on higher-value activities."}, {"title": "Maintenance requests requiring manual categorisation and routing", "description": "Tenant maintenance reports arrive with varying levels of detail and urgency. Staff must interpret each request, identify the appropriate trade, assess urgency, and route to the correct contractor — a repetitive process that scales linearly with portfolio size and is prone to inconsistency."}, {"title": "Landlord reports generated manually each month", "description": "Monthly landlord statements and management reports require compiling financial data, maintenance summaries, market commentary, and property updates from multiple sources. Manual report generation for a portfolio of fifty or more properties consumes days of staff time each month."}]',
  '[{"title": "AI tenant application pre-screening", "description": "AI analyses tenant applications against landlord-specific criteria — income multiples, employment status, reference requirements — and provides a recommendation with supporting evidence. Your team reviews pre-screened applications with a clear summary, dramatically reducing screening time while maintaining thorough due diligence."}, {"title": "Intelligent maintenance request triage", "description": "AI analyses maintenance request descriptions and photographs to identify the required trade, assess urgency level, and route to the appropriate approved contractor. Emergency issues are flagged for immediate action, routine requests are batched for efficient processing, and tenants receive instant acknowledgement with expected timelines."}, {"title": "Automated landlord reporting with market context", "description": "AI compiles monthly landlord reports combining financial performance data, maintenance activity summaries, market condition commentary, and property-specific updates. Each report is personalised to the landlord''s portfolio and presented in a branded format — produced in minutes rather than hours for every property under management."}]',
  '[{"question": "Can AI really screen tenant applications accurately?", "answer": "AI pre-screening applies consistent criteria to every application — income verification against rent multiples, employment status checks, and reference requirement matching. It produces a recommendation with supporting evidence for your team to review, ensuring thorough screening while reducing processing time by up to seventy percent."}, {"question": "How does AI categorise maintenance requests?", "answer": "The system analyses the tenant''s description and any uploaded photographs to identify the maintenance category, required trade, and urgency level. A photograph of a dripping tap is identified as plumbing and non-urgent; a report of no heating in winter is flagged as heating and urgent. Accuracy improves continuously through use."}, {"question": "Will AI-generated landlord reports feel generic?", "answer": "No. Each report is personalised with the specific landlord''s property data, financial performance, maintenance history, and relevant market conditions for their property''s area. The AI generates unique commentary for each portfolio based on actual management data, creating reports that feel individually crafted."}, {"question": "What is the ROI of AI automation for a letting agency?", "answer": "Most agencies recover the investment within the first month through staff time savings alone. Application screening, maintenance routing, and report generation that previously consumed hours of staff time per week are reduced to minutes. The larger benefit is enabling portfolio growth without proportional headcount increases."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;
